import{_ as a,c as r,o as t,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"z.ai 整合：能力邊界詳解 | Antigravity-Manager","description":"掌握 Antigravity Tools 的 z.ai 整合邊界。了解請求路由、dispatch_mode 分流、模型映射、Header 安全策略，以及 MCP 反代與限制，避免誤判。","frontmatter":{"title":"z.ai 整合：能力邊界詳解 | Antigravity-Manager","sidebarTitle":"z.ai 邊界速查","subtitle":"z.ai 整合：能力邊界詳解","description":"掌握 Antigravity Tools 的 z.ai 整合邊界。了解請求路由、dispatch_mode 分流、模型映射、Header 安全策略，以及 MCP 反代與限制，避免誤判。","tags":["z.ai","MCP","Claude","能力邊界"],"prerequisite":["start-getting-started","platforms-mcp"],"order":3},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"}'),i={name:"zh-tw/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"};function c(d,e,l,s,n,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="z-ai-整合的能力邊界-已實作-vs-明確未實作" tabindex="-1">z.ai 整合的能力邊界（已實作 vs 明確未實作） <a class="header-anchor" href="#z-ai-整合的能力邊界-已實作-vs-明確未實作" aria-label="Permalink to &quot;z.ai 整合的能力邊界（已實作 vs 明確未實作）&quot;">​</a></h1><p>這篇文件只講 Antigravity Tools 的 z.ai「邊界」，不講「怎麼接」。如果你發現某個能力沒生效，先來這裡對照一下：它到底是沒開、沒設，還是根本就沒實作。</p><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>判斷一件事該不該指望 z.ai：哪些是「已實作」，哪些是「文件明確沒做」</li><li>搞清 z.ai 只影響哪些端點（以及哪些端點完全不受影響）</li><li>看到每個結論的原始碼/文件證據（帶 GitHub 行號連結），方便你自己複核</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你可能在 Antigravity Tools 裡已經開啟了 z.ai，但一用就遇到這些疑惑：</p><ul><li>為什麼有些請求會走 z.ai，有些完全不走？</li><li>MCP 端點能不能當成「完整 MCP Server」？</li><li>UI 裡看得到的開關，到底有沒有對應到真實實作？</li></ul><h2 id="什麼是-z-ai-整合-在本專案裡" tabindex="-1">什麼是 z.ai 整合（在本專案裡）？ <a class="header-anchor" href="#什麼是-z-ai-整合-在本專案裡" aria-label="Permalink to &quot;什麼是 z.ai 整合（在本專案裡）？&quot;">​</a></h2><p><strong>z.ai 整合</strong>在 Antigravity Tools 裡是一個可選的「上游 provider + MCP 擴充」。它只在特定條件下接管 Claude 協議請求，並提供 MCP Search/Reader 反代與一個最小化的 Vision MCP 內建伺服器；它不是全協議、全能力的替換方案。</p><div class="info custom-block"><p class="custom-block-title">一句話記憶</p><p>你可以把 z.ai 當成「Claude 請求的可選上游 + 一組可開關的 MCP 端點」，別把它當成「把 z.ai 的所有能力完整搬進來」。</p></div><h2 id="已實作-穩定可用-以原始碼為準" tabindex="-1">已實作：穩定可用（以原始碼為準） <a class="header-anchor" href="#已實作-穩定可用-以原始碼為準" aria-label="Permalink to &quot;已實作：穩定可用（以原始碼為準）&quot;">​</a></h2><h3 id="_1-僅-claude-協議會走-z-ai-v1-messages-v1-messages-count-tokens" tabindex="-1">1) 僅 Claude 協議會走 z.ai（/v1/messages + /v1/messages/count_tokens） <a class="header-anchor" href="#_1-僅-claude-協議會走-z-ai-v1-messages-v1-messages-count-tokens" aria-label="Permalink to &quot;1) 僅 Claude 協議會走 z.ai（/v1/messages + /v1/messages/count_tokens）&quot;">​</a></h3><p>z.ai 的 Anthropic 上游轉發只在 Claude handler 的 z.ai 分支發生：</p><ul><li><code>POST /v1/messages</code>：當 <code>use_zai=true</code> 時呼叫 <code>forward_anthropic_json(...)</code> 把 JSON 請求轉發到 z.ai Anthropic 相容端點</li><li><code>POST /v1/messages/count_tokens</code>：當 z.ai 啟用時同樣轉發；否則傳回佔位的 <code>{input_tokens:0, output_tokens:0}</code></li></ul><p>證據：</p><ul><li>z.ai 分支選擇與轉發入口：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>count_tokens 的 z.ai 分支與佔位回傳：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>z.ai Anthropic 轉發實作：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><div class="tip custom-block"><p class="custom-block-title">「回應串流」怎麼理解？</p><p><code>forward_anthropic_json</code> 會把上游回應體以 <code>bytes_stream()</code> 串流回傳給客戶端，不解析 SSE（見 <code>providers/zai_anthropic.rs</code> 的 Response body 建構）。</p></div><h3 id="_2-排程模式-dispatch-mode-的「真實含義」" tabindex="-1">2) 排程模式（dispatch_mode）的「真實含義」 <a class="header-anchor" href="#_2-排程模式-dispatch-mode-的「真實含義」" aria-label="Permalink to &quot;2) 排程模式（dispatch_mode）的「真實含義」&quot;">​</a></h3><p><code>dispatch_mode</code> 決定 <code>/v1/messages</code> 是否走 z.ai：</p><table tabindex="0"><thead><tr><th>dispatch_mode</th><th>會發生什麼</th><th>證據</th></tr></thead><tbody><tr><td><code>off</code></td><td>永不使用 z.ai</td><td><code>src-tauri/src/proxy/config.rs#L20-L37</code> + <code>src-tauri/src/proxy/handlers/claude.rs#L282-L314</code></td></tr><tr><td><code>exclusive</code></td><td>所有 Claude 請求都走 z.ai</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L285-L314</code></td></tr><tr><td><code>fallback</code></td><td>Google 池不可用（0 帳號或「沒有可用帳號」）才走 z.ai</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L288-L305</code></td></tr><tr><td><code>pooled</code></td><td>把 z.ai 當作「額外 1 個槽位」參與輪詢（不保證一定命中）</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L306-L312</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">pooled 的常見誤解</p><p><code>pooled</code> 不是「z.ai + Google 帳號池都用，而且按權重穩定分流」。程式碼裡明確寫了「no strict guarantees」，本質是一個輪詢槽位（<code>slot == 0</code> 才走 z.ai）。</p></div><h3 id="_3-模型映射-claude-模型名稱怎麼變成-z-ai-的-glm" tabindex="-1">3) 模型映射：Claude 模型名稱怎麼變成 z.ai 的 glm-*？ <a class="header-anchor" href="#_3-模型映射-claude-模型名稱怎麼變成-z-ai-的-glm" aria-label="Permalink to &quot;3) 模型映射：Claude 模型名稱怎麼變成 z.ai 的 glm-*？&quot;">​</a></h3><p>在轉發到 z.ai 之前，如果請求體裡有 <code>model</code> 欄位，會被重寫：</p><ol><li><code>proxy.zai.model_mapping</code> 精確匹配（同時支援原串和 lower-case key）</li><li><code>zai:&lt;model&gt;</code> 前綴：去掉 <code>zai:</code> 直接用</li><li><code>glm-*</code>：保持不變</li><li>非 <code>claude-*</code>：保持不變</li><li><code>claude-*</code> 且包含 <code>opus/haiku</code>：映射到 <code>proxy.zai.models.opus/haiku</code>；否則預設 <code>sonnet</code></li></ol><p>證據：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L149-L152" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></p><h3 id="_4-轉發時的-header-安全策略-避免洩露本地-proxy-key" tabindex="-1">4) 轉發時的 Header 安全策略（避免洩露本地 proxy key） <a class="header-anchor" href="#_4-轉發時的-header-安全策略-避免洩露本地-proxy-key" aria-label="Permalink to &quot;4) 轉發時的 Header 安全策略（避免洩露本地 proxy key）&quot;">​</a></h3><p>z.ai 上游轉發不會「原樣帶所有 Header」，而是做了兩層防線：</p><ul><li>只放行一小部分 Header（例如 <code>content-type</code>、<code>accept</code>、<code>anthropic-version</code>、<code>user-agent</code>）</li><li>把 z.ai 的 API Key 注入到上游（優先保持客戶端用的鑑權方式：<code>x-api-key</code> 或 <code>Authorization: Bearer ...</code>）</li></ul><p>證據：</p><ul><li>Header 白名單：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L89" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li><li>注入 z.ai auth：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L91-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><h2 id="已實作-mcp-search-reader-反代-vision-內建" tabindex="-1">已實作：MCP（Search/Reader 反代 + Vision 內建） <a class="header-anchor" href="#已實作-mcp-search-reader-反代-vision-內建" aria-label="Permalink to &quot;已實作：MCP（Search/Reader 反代 + Vision 內建）&quot;">​</a></h2><h3 id="_1-mcp-search-reader-反向代理到-z-ai-的-mcp-端點" tabindex="-1">1) MCP Search/Reader：反向代理到 z.ai 的 MCP 端點 <a class="header-anchor" href="#_1-mcp-search-reader-反向代理到-z-ai-的-mcp-端點" aria-label="Permalink to &quot;1) MCP Search/Reader：反向代理到 z.ai 的 MCP 端點&quot;">​</a></h3><p>本地端點與上游位址是寫死的：</p><table tabindex="0"><thead><tr><th>本地端點</th><th>上游位址</th><th>開關</th><th>證據</th></tr></thead><tbody><tr><td><code>/mcp/web_search_prime/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_search_prime/mcp</code></td><td><code>proxy.zai.mcp.web_search_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L115-L135</code></td></tr><tr><td><code>/mcp/web_reader/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_reader/mcp</code></td><td><code>proxy.zai.mcp.web_reader_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L137-L157</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">404 不是「網路問題」</p><p>只要 <code>proxy.zai.mcp.enabled=false</code>，或者對應 <code>web_search_enabled/web_reader_enabled=false</code>，這些端點就會直接傳回 404。</p></div><p>證據：</p><ul><li>MCP 總開關與 z.ai key 校驗：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L52-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>路由註冊：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L157-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></li></ul><h3 id="_2-vision-mcp-一個「最小化-streamable-http-mcp」內建伺服器" tabindex="-1">2) Vision MCP：一個「最小化 Streamable HTTP MCP」內建伺服器 <a class="header-anchor" href="#_2-vision-mcp-一個「最小化-streamable-http-mcp」內建伺服器" aria-label="Permalink to &quot;2) Vision MCP：一個「最小化 Streamable HTTP MCP」內建伺服器&quot;">​</a></h3><p>Vision MCP 不是反代，它是本地內建實作：</p><ul><li>端點：<code>/mcp/zai-mcp-server/mcp</code></li><li><code>POST</code> 支援：<code>initialize</code>、<code>tools/list</code>、<code>tools/call</code></li><li><code>GET</code> 傳回 SSE keepalive（要求已初始化的 session）</li><li><code>DELETE</code> 結束 session</li></ul><p>證據：</p><ul><li>handler 主入口與方法分發：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L376-L397" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li><code>initialize</code>、<code>tools/list</code>、<code>tools/call</code> 的實作：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L229-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Vision MCP 的「最小實作」定位：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></li></ul><h3 id="_3-vision-mcp-工具集-8-個-與檔案大小限制" tabindex="-1">3) Vision MCP 工具集（8 個）與檔案大小限制 <a class="header-anchor" href="#_3-vision-mcp-工具集-8-個-與檔案大小限制" aria-label="Permalink to &quot;3) Vision MCP 工具集（8 個）與檔案大小限制&quot;">​</a></h3><p>工具列表來自 <code>tool_specs()</code>：</p><ul><li><code>ui_to_artifact</code></li><li><code>extract_text_from_screenshot</code></li><li><code>diagnose_error_screenshot</code></li><li><code>understand_technical_diagram</code></li><li><code>analyze_data_visualization</code></li><li><code>ui_diff_check</code></li><li><code>analyze_image</code></li><li><code>analyze_video</code></li></ul><p>證據：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L166-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L45-L53" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></p><p>本地檔案會被讀出來並編碼成 <code>data:&lt;mime&gt;;base64,...</code>，同時有硬限制：</p><ul><li>圖片上限 5 MB（<code>image_source_to_content(..., 5)</code>）</li><li>影片上限 8 MB（<code>video_source_to_content(..., 8)</code>）</li></ul><p>證據：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L111" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></p><h2 id="明確未實作-不要期待-以文件宣告與實作細節為準" tabindex="-1">明確未實作 / 不要期待（以文件宣告與實作細節為準） <a class="header-anchor" href="#明確未實作-不要期待-以文件宣告與實作細節為準" aria-label="Permalink to &quot;明確未實作 / 不要期待（以文件宣告與實作細節為準）&quot;">​</a></h2><h3 id="_1-z-ai-用量-預算監控-usage-budget-未實作" tabindex="-1">1) z.ai 用量/預算監控（usage/budget）未實作 <a class="header-anchor" href="#_1-z-ai-用量-預算監控-usage-budget-未實作" aria-label="Permalink to &quot;1) z.ai 用量/預算監控（usage/budget）未實作&quot;">​</a></h3><p><code>docs/zai/implementation.md</code> 明確寫了「not implemented yet」。這意味著：</p><ul><li>你不能指望 Antigravity Tools 提供 z.ai 的 usage/budget 查詢或告警</li><li>配額治理（Quota Protection）也不會自動讀 z.ai 的預算/用量資料</li></ul><p>證據：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_2-vision-mcp-不是完整-mcp-server" tabindex="-1">2) Vision MCP 不是完整 MCP Server <a class="header-anchor" href="#_2-vision-mcp-不是完整-mcp-server" aria-label="Permalink to &quot;2) Vision MCP 不是完整 MCP Server&quot;">​</a></h3><p>Vision MCP 目前定位就是「只夠工具呼叫」的最小實作：prompts/resources、resumability、streamed tool output 等都還沒做。</p><p>證據：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L34-L36" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_3-v1-models-claude-不會反映-z-ai-的真實模型列表" tabindex="-1">3) <code>/v1/models/claude</code> 不會反映 z.ai 的真實模型列表 <a class="header-anchor" href="#_3-v1-models-claude-不會反映-z-ai-的真實模型列表" aria-label="Permalink to &quot;3) `/v1/models/claude` 不會反映 z.ai 的真實模型列表&quot;">​</a></h3><p>這個端點傳回的模型列表來自本地內建映射與自訂映射（<code>get_all_dynamic_models</code>），不會去請求 z.ai 上游的 <code>/v1/models</code>。</p><p>證據：</p><ul><li>handler：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1162-L1183" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>列表生成邏輯：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></li></ul><h2 id="設定欄位速查-z-ai-相關" tabindex="-1">設定欄位速查（z.ai 相關） <a class="header-anchor" href="#設定欄位速查-z-ai-相關" aria-label="Permalink to &quot;設定欄位速查（z.ai 相關）&quot;">​</a></h2><p>z.ai 設定在 <code>ProxyConfig.zai</code> 下，包含這些欄位：</p><ul><li><code>enabled</code> / <code>base_url</code> / <code>api_key</code></li><li><code>dispatch_mode</code>（<code>off/exclusive/pooled/fallback</code>）</li><li><code>model_mapping</code>（精確匹配覆寫）</li><li><code>models.{opus,sonnet,haiku}</code>（Claude 家族預設映射）</li><li><code>mcp.{enabled,web_search_enabled,web_reader_enabled,vision_enabled}</code></li></ul><p>預設值（base_url / 預設模型）也在同一個檔案裡：</p><ul><li><code>base_url = &quot;https://api.z.ai/api/anthropic&quot;</code></li><li><code>opus/sonnet = &quot;glm-4.7&quot;</code></li><li><code>haiku = &quot;glm-4.5-air&quot;</code></li></ul><h2 id="證據-src-tauri-src-proxy-config-rs、src-tauri-src-proxy-config-rs" tabindex="-1">證據：<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a>、<a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a> <a class="header-anchor" href="#證據-src-tauri-src-proxy-config-rs、src-tauri-src-proxy-config-rs" aria-label="Permalink to &quot;證據：[`src-tauri/src/proxy/config.rs`](https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116)、[`src-tauri/src/proxy/config.rs`](https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279)&quot;">​</a></h2><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>z.ai 目前只會接管 Claude 協議（<code>/v1/messages</code> + <code>count_tokens</code>），其他協議端點不是「自動走 z.ai」</li><li>MCP Search/Reader 是反代；Vision MCP 是本地最小實作，不是完整 MCP Server</li><li><code>/v1/models/claude</code> 的模型列表來自本地映射，不代表 z.ai 上游真實模型</li></ul><hr><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../../changelog/release-notes/">版本演進</a></strong>。</p></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>z.ai 整合範圍（Claude 協議 + MCP + Vision MCP）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L12-L17" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>12-17</td></tr><tr><td>z.ai 排程模式與模型預設值</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>20-116</td></tr><tr><td>z.ai 預設 base_url / 預設模型</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>265-279</td></tr><tr><td><code>/v1/messages</code> 是否走 z.ai 的選擇邏輯</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>256-374</td></tr><tr><td><code>/v1/messages/count_tokens</code> 的 z.ai 轉發與佔位回傳</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>1186-1209</td></tr><tr><td>z.ai Anthropic 上游轉發（JSON 轉發 + 回應串流回傳）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>133-219</td></tr><tr><td>z.ai 模型映射規則（map_model_for_zai）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>13-37</td></tr><tr><td>Header 白名單 + 注入 z.ai auth</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>70-110</td></tr><tr><td>MCP Search/Reader 反代與開關</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L45-L157" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></td><td>45-157</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Vision MCP 最小實作定位（非完整 MCP Server）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></td><td>17-37</td></tr><tr><td>Vision 工具列表與限制（tool_specs + 檔案大小 + stream=false）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></td><td>57-270</td></tr><tr><td><code>/v1/models/claude</code> 模型列表來源（本地映射，不查上游）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>84-132</td></tr><tr><td>用量/預算監控未實作（文件宣告）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>194-198</td></tr></tbody></table></details>',75)])])}const b=a(i,[["render",c]]);export{u as __pageData,b as default};
